@Test public void orphanedElementWithAttributes() {
    Element div = new Element("div");
    div.attr("class", "test");
    div.attr("id", "myDiv");
    assertEquals("<div class=\"test\" id=\"myDiv\"></div>", div.toString());
}

@Test public void orphanedElementWithChildren() {
    Element parent = new Element("div");
    Element child = new Element("span");
    child.text("Hello");
    parent.appendChild(child);
    parent.remove();
    assertEquals("<div>\n <span>Hello</span>\n</div>", parent.toString());
}

@Test public void orphanedSelfClosingElement() {
    Element br = new Element("br");
    assertEquals("<br />", br.toString());
}
